public void insert()
{
    ETG_PostPackingQualityGrp    eTG_PostPackingQualityGrp;
    Salesparmline                 salesparmline;
    ETG_CustPackingQualityGrp     etg_CustPackingQualityGrp;
    ETG_BOLCarrierTable           carrierTable;

    next insert();

    select firstonly ParmId from  salesparmline order by ParmId desc
        where salesparmline.OrigSalesId == this.SalesId;


    while select * from eTG_PostPackingQualityGrp where eTG_PostPackingQualityGrp.ParmId == salesparmline.ParmId
    {
        etg_CustPackingQualityGrp.GroupID         = eTG_PostPackingQualityGrp.GroupID;
        etg_CustPackingQualityGrp.MaxRange        = eTG_PostPackingQualityGrp.MaxRange;
        etg_CustPackingQualityGrp.MinRange        = eTG_PostPackingQualityGrp.MinRange;
       // eTG_PostPackingQualityGrp.ParmId          = _salesParmLine.ParmId;
        etg_CustPackingQualityGrp.SubGroupID      = eTG_PostPackingQualityGrp.SubGroupID;
        etg_CustPackingQualityGrp.MeasurementType = eTG_PostPackingQualityGrp.MeasurementType;
        etg_CustPackingQualityGrp.AdjustmentType  = eTG_PostPackingQualityGrp.AdjustmentType;
        etg_CustPackingQualityGrp.Increment       = eTG_PostPackingQualityGrp.Increment;
        etg_CustPackingQualityGrp.FixedValue      = eTG_PostPackingQualityGrp.FixedValue;
        etg_CustPackingQualityGrp.ResultValue     = eTG_PostPackingQualityGrp.ResultValue;
        etg_CustPackingQualityGrp.SubGroupDescription  = eTG_PostPackingQualityGrp.SubGroupDescription;
        //this.PackingSlipId                                     ;
        etg_CustPackingQualityGrp.insert();
    }


}
